/**
 * Injectable copy of styles.css. Keep in sync with scripts/sync-ui-css.mjs.
 */

export const GF_UI_CSS = "/*\r\n * Gotcha Force — shared UI styles for the 1-to-1 recreation component library.\r\n *\r\n * All classes are prefixed `gf-` to stay scoped. Palette + type feel are pulled\r\n * from the real captured reference screens in apps/game/reference/captures/.\r\n * Reference real extracted art via /ui/... public paths (see ASSETS const in TS).\r\n *\r\n * Injected automatically by ui/index.ts (ensureStyles); also importable directly\r\n * by a bundler that handles CSS imports.\r\n */\r\n\r\n:root {\r\n  /* Core palette sampled from the reference captures. */\r\n  --gf-yellow: #ffd21e;          /* SELECT DIFFICULTY title fill */\r\n  --gf-yellow-deep: #f5a800;     /* WIN gold */\r\n  --gf-outline: #2a2150;         /* dark title/text outline (purple-navy) */\r\n  --gf-green: #46c828;           /* ALLY meter / FIGHT ALONE ring / A button */\r\n  --gf-green-deep: #1f8a14;\r\n  --gf-red: #e8231b;             /* ENEMY meter / B button / INSANE pad */\r\n  --gf-red-deep: #a40d0d;\r\n  --gf-blue-pill: #5b9bd5;       /* results row pills */\r\n  --gf-blue-pill-deep: #2f6db0;\r\n  --gf-orange: #ff7a18;          /* TUFF pad / value numbers */\r\n  --gf-cyan: #34e0d8;            /* reload bar */\r\n  --gf-panel: #d9d9d9;           /* light HUD panel */\r\n  --gf-edit-purple: #6b4ad0;     /* pause box border / force ring */\r\n  --gf-text-cream: #fff4d8;\r\n  --gf-text-light: #eef4ff;\r\n}\r\n\r\n/* Generic full-screen menu surface that hosts a screen component. */\r\n.gf-screen {\r\n  position: relative;\r\n  width: 100%;\r\n  height: 100%;\r\n  min-height: 100%;\r\n  box-sizing: border-box;\r\n  overflow: hidden;\r\n  color: var(--gf-text-light);\r\n  font-family: \"Trebuchet MS\", \"Segoe UI\", Arial, sans-serif;\r\n  font-weight: 800;\r\n  letter-spacing: 0.02em;\r\n  user-select: none;\r\n  -webkit-user-select: none;\r\n}\r\n\r\n.gf-ui-scene {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 1;\r\n  pointer-events: none;\r\n}\r\n.gf-ui-scene-canvas {\r\n  display: block;\r\n  width: 100%;\r\n  height: 100%;\r\n}\r\n\r\n/* Gridded radial backdrop used by the menu screens (difficulty/players/force). */\r\n.gf-grid-bg {\r\n  position: absolute;\r\n  inset: 0;\r\n  background:\r\n    radial-gradient(circle at 50% 42%, rgba(255, 255, 255, 0.35), transparent 60%),\r\n    repeating-linear-gradient(0deg, rgba(255, 255, 255, 0.08) 0 1px, transparent 1px 34px),\r\n    repeating-linear-gradient(90deg, rgba(255, 255, 255, 0.08) 0 1px, transparent 1px 34px);\r\n  background-color: var(--gf-screen-bg, #2f7fd0);\r\n}\r\n.gf-grid-bg.gf-bg-blue { --gf-screen-bg: #2f7fd0; }\r\n.gf-grid-bg.gf-bg-green { --gf-screen-bg: #4caa2f; }\r\n.gf-grid-bg.gf-bg-purple { --gf-screen-bg: #8b4fb5; }\r\n.gf-grid-bg.gf-bg-gold { --gf-screen-bg: #f3a312; }\r\n\r\n/*\r\n * The vsel00/vsel01 GLB exports contain real pad/gear/backdrop/silhouette\r\n * geometry, but each archive bundles EVERY vsel/challenge-select sub-menu\r\n * (plus, for vsel00, 40 unrelated stage-preview dioramas) into one 165-model\r\n * scene with no recoverable per-sub-menu grouping, so it cannot be reliably\r\n * auto-fit to just the relevant cluster. It is mounted as atmospheric\r\n * backdrop decoration (see SelectDifficulty.ts / SelectPlayers.ts); the pad\r\n * tiles themselves use cropped real captured native frames instead (see\r\n * cropImgStyle in SelectDifficulty.ts).\r\n */\r\n.gf-vsel-real-scene {\r\n  opacity: 0.36;\r\n  transform: scale(1.03);\r\n  filter: drop-shadow(0 20px 18px rgba(0, 0, 0, 0.32));\r\n}\r\n\r\n.gf-vsel-screen {\r\n  display: grid;\r\n  place-items: center;\r\n  background: var(--gf-vsel-outer, #2f7fd0);\r\n}\r\n.gf-vsel-frame {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 50%;\r\n  width: min(100vw, calc(100vh * 4 / 3));\r\n  max-height: 100vh;\r\n  aspect-ratio: 4 / 3;\r\n  transform: translate(-50%, -50%);\r\n  overflow: hidden;\r\n}\r\n.gf-select-difficulty {\r\n  --gf-vsel-outer: #1a75d9;\r\n}\r\n.gf-select-players {\r\n  --gf-vsel-outer: #168c20;\r\n}\r\n.gf-vsel-screen .gf-title {\r\n  position: absolute;\r\n  left: 0;\r\n  right: 0;\r\n  top: 25.8%;\r\n  z-index: 3;\r\n  padding-top: 0;\r\n  display: flex;\r\n  justify-content: center;\r\n  opacity: var(--gf-title-opacity, 1);\r\n  transform: translateY(var(--gf-title-offset-y, 0%)) scale(var(--gf-title-scale, 1));\r\n  transform-origin: 50% 55%;\r\n}\r\n/* Real ascii.tpl bitmap-font rendering of the vsel title (SELECT DIFFICULTY / SELECT NUMBER OF PLAYERS). */\r\n.gf-vsel-title-text {\r\n  transform: scale(var(--gf-vsel-title-fit, 1));\r\n}\r\n.gf-vsel-screen .gf-vsel-options {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 4;\r\n  display: block;\r\n}\r\n\r\n/* Chunky outlined arcade title (SELECT DIFFICULTY, SELECT A FORCE, ...). */\r\n.gf-title {\r\n  position: relative;\r\n  z-index: 2;\r\n  text-align: center;\r\n  margin: 0;\r\n  padding-top: 0.6em;\r\n  font-size: clamp(22px, 4.4vw, 40px);\r\n  color: var(--gf-yellow);\r\n  letter-spacing: 0.06em;\r\n  text-transform: uppercase;\r\n  -webkit-text-stroke: 2px var(--gf-outline);\r\n  paint-order: stroke fill;\r\n  text-shadow: 0 4px 0 rgba(0, 0, 0, 0.35);\r\n}\r\n\r\n.gf-row {\r\n  position: relative;\r\n  z-index: 2;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  gap: clamp(16px, 5vw, 64px);\r\n}\r\n\r\n/* Bottom button legend shared by menu screens. */\r\n.gf-legend {\r\n  position: absolute;\r\n  left: 0;\r\n  right: 0;\r\n  bottom: 18px;\r\n  z-index: 3;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  gap: clamp(20px, 6vw, 64px);\r\n  font-size: clamp(13px, 2vw, 18px);\r\n}\r\n.gf-legend-item {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  gap: 8px;\r\n  color: #ffffff;\r\n  text-shadow: 0 2px 0 rgba(0, 0, 0, 0.45);\r\n}\r\n\r\n/* The round face-button glyphs (A green / B red / X grey / Y / START). */\r\n.gf-btn {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  justify-content: center;\r\n  width: 1.7em;\r\n  height: 1.7em;\r\n  border-radius: 50%;\r\n  font-size: 0.9em;\r\n  color: #ffffff;\r\n  font-weight: 900;\r\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.35), 0 2px 3px rgba(0, 0, 0, 0.4);\r\n}\r\n.gf-btn-a { background: radial-gradient(circle at 35% 30%, #6fe24a, var(--gf-green-deep)); }\r\n.gf-btn-b { background: radial-gradient(circle at 35% 30%, #ff5a4f, var(--gf-red-deep)); }\r\n.gf-btn-x { background: radial-gradient(circle at 35% 30%, #cfd3da, #7d828c); color: #2a2150; }\r\n.gf-btn-y { background: radial-gradient(circle at 35% 30%, #6fc3ff, #2f6db0); }\r\n.gf-btn-start { background: radial-gradient(circle at 35% 30%, #cfd3da, #7d828c); color: #2a2150; font-size: 0.62em; }\r\n\r\n.gf-bitmap-text {\r\n  display: inline-flex;\r\n  align-items: center;\r\n  gap: 1px;\r\n  image-rendering: pixelated;\r\n  font-size: 0;\r\n}\r\n.gf-bitmap-glyph,\r\n.gf-bitmap-space {\r\n  display: inline-block;\r\n  width: 8px;\r\n  height: 8px;\r\n  flex: 0 0 auto;\r\n}\r\n.gf-bitmap-glyph {\r\n  background-repeat: no-repeat;\r\n  background-size: 128px 128px;\r\n}\r\n.gf-bitmap-fallback {\r\n  display: inline-block;\r\n  font-size: 8px;\r\n  line-height: 8px;\r\n}\r\n\r\n/* Generic option tile used by difficulty + players screens. */\r\n.gf-option {\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  gap: 6px;\r\n  cursor: pointer;\r\n  background: none;\r\n  border: none;\r\n  color: inherit;\r\n  font: inherit;\r\n  padding: 8px;\r\n  transition: transform 0.12s ease;\r\n}\r\n.gf-option:hover { transform: translateY(-2px); }\r\n.gf-option.gf-selected { transform: scale(1.06); }\r\n\r\n.gf-vsel-screen .gf-option {\r\n  position: absolute;\r\n  padding: 0;\r\n  gap: 0;\r\n  transform:\r\n    translate(\r\n      calc(-50% + var(--gf-enter-offset-x, 0%)),\r\n      calc(-50% + var(--gf-enter-offset-y, 0%))\r\n    )\r\n    scale(var(--gf-select-scale, 1));\r\n  opacity: var(--gf-enter-opacity, 1);\r\n  will-change: transform, opacity;\r\n  transition: filter 100ms linear;\r\n}\r\n.gf-vsel-screen .gf-option:hover,\r\n.gf-vsel-screen .gf-option.gf-selected {\r\n  transform:\r\n    translate(\r\n      calc(-50% + var(--gf-enter-offset-x, 0%)),\r\n      calc(-50% + var(--gf-enter-offset-y, 0%))\r\n    )\r\n    scale(var(--gf-select-scale, 1));\r\n}\r\n.gf-vsel-screen .gf-motion-object {\r\n  transform:\r\n    translate(\r\n      calc(-50% + var(--gf-enter-offset-x, 0%)),\r\n      calc(-50% + var(--gf-enter-offset-y, 0%))\r\n    )\r\n    scale(var(--gf-select-scale, 1));\r\n  opacity: var(--gf-enter-opacity, 1);\r\n  will-change: transform, opacity;\r\n}\r\n.gf-vsel-screen .gf-option.gf-selected {\r\n  z-index: 2;\r\n}\r\n.gf-vsel-screen .gf-option.gf-selected::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 42%;\r\n  width: 105%;\r\n  aspect-ratio: 1;\r\n  transform: translate(-50%, -50%) scale(var(--gf-ring-scale, 1));\r\n  border-radius: 50%;\r\n  background: #050505;\r\n  z-index: -1;\r\n  filter: drop-shadow(0 8px 0 rgba(0, 0, 0, 0.18));\r\n  opacity: var(--gf-ring-opacity, 1);\r\n}\r\n/*\r\n * Row center X/Y comes from the vsel00 scene export (option-stage ellipse) via\r\n * --gf-diff-row-top / --gf-diff-center-x set in SelectDifficulty.ts; the pad\r\n * spread (+-28.5% / +-27.5%) stays hand-tuned because the export stacks the\r\n * pads at the scene center. Fallbacks preserve the previous hand-tuned layout.\r\n */\r\n.gf-diff-option {\r\n  top: var(--gf-diff-row-top, 64%);\r\n  width: 22%;\r\n}\r\n.gf-diff-normal {\r\n  left: calc(var(--gf-diff-center-x, 51%) - 28.5%);\r\n  width: 29.5%;\r\n}\r\n.gf-diff-tuff {\r\n  left: var(--gf-diff-center-x, 51%);\r\n}\r\n.gf-diff-insane {\r\n  left: calc(var(--gf-diff-center-x, 51%) + 27.5%);\r\n}\r\n/*\r\n * Each pad tile shows a cropped region of the real captured native frame\r\n * (reference/captures/challenge-2-select-difficulty.png — see\r\n * SelectDifficulty.ts), which already bakes in the \"GF ENERGY <n> <NAME>\"\r\n * art pixel-for-pixel, so no separate CSS/bitmap-font callout is layered on\r\n * top. `.gf-diff-pad-crop` is the fixed-aspect crop window; the inner `<img>`\r\n * is the full capture, scaled + shifted (see cropImgStyle) so only that\r\n * window's pixels show.\r\n */\r\n.gf-diff-pad-crop {\r\n  position: relative;\r\n  width: 100%;\r\n  overflow: hidden;\r\n  border-radius: 8%;\r\n}\r\n.gf-capture-crop-img {\r\n  display: block;\r\n  image-rendering: -webkit-optimize-contrast;\r\n}\r\n\r\n.gf-player-option {\r\n  top: 61.5%;\r\n}\r\n.gf-player-1 {\r\n  left: 31%;\r\n  width: 31%;\r\n}\r\n.gf-player-2 {\r\n  left: 71%;\r\n  width: 31%;\r\n}\r\n/*\r\n * Each tile shows a cropped region of the real captured native frame\r\n * (reference/captures/challenge-3-select-players.png — see\r\n * SelectPlayers.ts), which already bakes in the silhouette/pill-label/\r\n * controller art pixel-for-pixel, so no separate CSS silhouette/pill/\r\n * controller recreation is layered on top.\r\n */\r\n.gf-player-tile-crop {\r\n  position: relative;\r\n  width: 100%;\r\n  overflow: hidden;\r\n}\r\n.gf-player-arrow {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 59.5%;\r\n  z-index: 4;\r\n  width: 7.2%;\r\n  transform: translate(-50%, -50%);\r\n  overflow: hidden;\r\n  border-radius: 50%;\r\n}\r\n\r\n/* ============================ TITLE INTRO ============================ */\r\n/* Source-shaped desk/title intro (research/decomp/index/title-main-menu-flow.md):\r\n * real tl00 scene backdrop + the G-Red desk-intro actor, replacing the old handcoded\r\n * CSS gear backdrop for this screen. \"Press start\" advances to the main menu, modeling\r\n * the title_main_menu_scene_enter -> set_global_menu_mode(9) handoff. */\r\n.gf-title-intro {\r\n  background: #10131c;\r\n  cursor: pointer;\r\n}\r\n.gf-title-intro-scene {\r\n  z-index: 1;\r\n}\r\n/* Native captured title/desk frame (reference/captures/title-main-menu.png) — cover-fit,\r\n * slightly dimmed so the G-Red actor layer and PRESS START read on top. */\r\n.gf-title-intro-backdrop {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 1;\r\n  background-size: cover;\r\n  background-position: center;\r\n  filter: brightness(0.9);\r\n}\r\n/* Real tl00 3D desk scene through its authored HSD camera — sits over the capture\r\n * (which stays as instant paint + load-failure fallback) and under the actor layer. */\r\n.gf-title-intro-desk {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 1;\r\n}\r\n.gf-title-intro-actor {\r\n  z-index: 2;\r\n}\r\n.gf-title-intro-source-title {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 15%;\r\n  z-index: 3;\r\n  max-width: 92%;\r\n  transform: translateX(-50%) scale(0.92);\r\n  transform-origin: 50% 50%;\r\n  opacity: 0;\r\n  color: #ffd21e;\r\n  font-size: clamp(30px, 7vh, 86px);\r\n  line-height: 0.92;\r\n  letter-spacing: 0;\r\n  white-space: nowrap;\r\n  -webkit-text-stroke: clamp(2px, 0.45vh, 5px) #071126;\r\n  paint-order: stroke fill;\r\n  text-shadow:\r\n    0 3px 0 #ffffff,\r\n    0 7px 0 rgba(0, 0, 0, 0.55),\r\n    0 0 18px rgba(255, 241, 126, 0.55);\r\n  pointer-events: none;\r\n  transition:\r\n    opacity 120ms linear,\r\n    transform 120ms linear;\r\n}\r\n.gf-title-intro[data-gf-intro-step=\"9\"] .gf-title-intro-source-title,\r\n.gf-title-intro[data-gf-intro-step=\"10\"] .gf-title-intro-source-title,\r\n.gf-title-intro[data-gf-intro-step=\"11\"] .gf-title-intro-source-title,\r\n.gf-title-intro[data-gf-intro-step=\"12\"] .gf-title-intro-source-title,\r\n.gf-title-intro[data-gf-intro-done=\"true\"] .gf-title-intro-source-title {\r\n  opacity: 1;\r\n  transform: translateX(-50%) scale(1);\r\n}\r\n.gf-title-intro-lightbar {\r\n  position: absolute;\r\n  left: -38%;\r\n  top: 66%;\r\n  z-index: 4;\r\n  width: 42%;\r\n  height: clamp(4px, 0.8vh, 8px);\r\n  opacity: 0;\r\n  transform: skewX(-18deg);\r\n  transform-origin: 50% 50%;\r\n  background: linear-gradient(\r\n    90deg,\r\n    transparent 0%,\r\n    rgba(97, 228, 255, 0.2) 18%,\r\n    #ffffff 50%,\r\n    rgba(120, 246, 255, 0.85) 70%,\r\n    transparent 100%\r\n  );\r\n  box-shadow:\r\n    0 0 10px rgba(255, 255, 255, 0.95),\r\n    0 0 26px rgba(70, 224, 255, 0.88),\r\n    0 0 54px rgba(70, 224, 255, 0.42);\r\n  pointer-events: none;\r\n}\r\n.gf-title-intro[data-gf-lightbar=\"active\"] .gf-title-intro-lightbar {\r\n  opacity: 1;\r\n  animation: gf-title-lightbar-sweep 700ms linear both;\r\n}\r\n.gf-title-intro-prompt {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 8%;\r\n  z-index: 3;\r\n  transform: translateX(-50%);\r\n  color: var(--gf-yellow);\r\n  font-size: clamp(18px, 3.4vw, 34px);\r\n  letter-spacing: 0;\r\n  -webkit-text-stroke: clamp(1.5px, 0.28vw, 4px) #071126;\r\n  paint-order: stroke fill;\r\n  text-shadow: 0 3px 0 #ffffff, 0 6px 0 rgba(0, 0, 0, 0.5);\r\n  opacity: 0;\r\n  animation: none;\r\n  pointer-events: none;\r\n}\r\n.gf-title-intro[data-gf-intro-step=\"12\"] .gf-title-intro-prompt,\r\n.gf-title-intro[data-gf-intro-done=\"true\"] .gf-title-intro-prompt {\r\n  opacity: 1;\r\n  animation: gf-title-prompt-blink 1.4s ease-in-out infinite;\r\n}\r\n@keyframes gf-title-lightbar-sweep {\r\n  from {\r\n    transform: translateX(0) skewX(-18deg);\r\n  }\r\n  to {\r\n    transform: translateX(340%) skewX(-18deg);\r\n  }\r\n}\r\n@keyframes gf-title-prompt-blink {\r\n  0%, 55% { opacity: 1; }\r\n  78% { opacity: 0.25; }\r\n  100% { opacity: 1; }\r\n}\r\n\r\n/* ============================ MAIN MENU ============================ */\r\n.gf-mainmenu {\r\n  background: #6eb6d7;\r\n}\r\n.gf-mainmenu-frame {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 50%;\r\n  width: min(100%, calc(100vh * 4 / 3));\r\n  max-height: 100%;\r\n  aspect-ratio: 4 / 3;\r\n  transform: translate(-50%, -50%);\r\n  overflow: hidden;\r\n  background: #58a9ca;\r\n  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.2);\r\n}\r\n.gf-mainmenu-scene {\r\n  opacity: 0;\r\n  transform: scale(1.02);\r\n  transition: opacity var(--gf-native-tween-ms, 167ms) linear;\r\n}\r\n.gf-mainmenu[data-native-capture=\"false\"][data-menu-scene=\"hub\"] .gf-mainmenu-hub-scene {\r\n  opacity: 0.32;\r\n}\r\n.gf-mainmenu[data-native-capture=\"false\"][data-menu-scene=\"option\"] .gf-mainmenu-option-scene {\r\n  opacity: 0.42;\r\n  transform: scale(1.08);\r\n  filter: drop-shadow(0 18px 18px rgba(0, 0, 0, 0.34));\r\n}\r\n.gf-mainmenu-desk {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 1;\r\n  background-size: 100% 100%;\r\n  background-position: center;\r\n  background-repeat: no-repeat;\r\n  image-rendering: pixelated;\r\n  transition:\r\n    opacity var(--gf-native-tween-ms, 167ms) linear,\r\n    filter var(--gf-native-tween-ms, 167ms) linear;\r\n}\r\n.gf-mainmenu[data-native-capture=\"false\"] .gf-mainmenu-desk {\r\n  opacity: 0.88;\r\n  filter: saturate(0.96) brightness(0.94);\r\n}\r\n.gf-mainmenu-desk::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  inset: 0;\r\n  background: linear-gradient(180deg, rgba(255, 255, 255, 0.04), rgba(0, 0, 0, 0.1));\r\n  pointer-events: none;\r\n}\r\n.gf-mainmenu-ring {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 2;\r\n}\r\n.gf-menu-item {\r\n  position: absolute;\r\n  transform: translate(-50%, -50%);\r\n  cursor: pointer;\r\n  background: none;\r\n  border: none;\r\n  padding: 0;\r\n  opacity: 0;\r\n  outline: none;\r\n}\r\n.gf-menu-item:focus-visible {\r\n  opacity: 1;\r\n  border-radius: 50%;\r\n  box-shadow: 0 0 0 3px rgba(255, 255, 255, 0.86), 0 0 0 7px rgba(232, 35, 27, 0.55);\r\n}\r\n.gf-menu-item.gf-selected:focus-visible {\r\n  box-shadow: 0 0 0 4px rgba(255, 255, 255, 0.92), 0 0 0 9px rgba(232, 35, 27, 0.72);\r\n}\r\n.gf-menu-cursor {\r\n  position: absolute;\r\n  transform: translate(-50%, -50%);\r\n  pointer-events: none;\r\n  border-radius: 50%;\r\n  opacity: 0;\r\n  transition:\r\n    left var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    top var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    width var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    height var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    opacity var(--gf-native-tween-ms, 167ms) linear;\r\n}\r\n.gf-mainmenu[data-native-capture=\"false\"] .gf-menu-cursor {\r\n  opacity: 0.9;\r\n}\r\n.gf-menu-cursor::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 50%;\r\n  width: min(124px, 84%);\r\n  aspect-ratio: 1;\r\n  transform: translate(-50%, -50%);\r\n  border-radius: 50%;\r\n  background:\r\n    conic-gradient(from 11deg, #7e160f 0 8deg, transparent 8deg 22deg),\r\n    radial-gradient(circle at 35% 30%, #ff8a4a, var(--gf-red));\r\n  box-shadow:\r\n    inset 0 -4px 0 rgba(0, 0, 0, 0.38),\r\n    inset 0 0 0 11px rgba(255, 255, 255, 0.22),\r\n    0 0 0 5px rgba(255, 255, 255, 0.86),\r\n    0 0 0 12px rgba(232, 35, 27, 0.9),\r\n    0 8px 10px rgba(0, 0, 0, 0.42);\r\n  animation: gf-gear-spin 6s linear infinite;\r\n}\r\n@keyframes gf-gear-spin { to { transform: translate(-50%, -50%) rotate(360deg); } }\r\n.gf-mainmenu-selected-proxy {\r\n  position: absolute;\r\n  transform: translate(-50%, -50%);\r\n  display: grid;\r\n  place-items: center;\r\n  pointer-events: none;\r\n  opacity: 0;\r\n  transition:\r\n    left var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    top var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    width var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    height var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1),\r\n    opacity var(--gf-native-tween-ms, 167ms) linear,\r\n    transform var(--gf-native-tween-ms, 167ms) cubic-bezier(0.2, 0.76, 0.22, 1);\r\n}\r\n.gf-mainmenu[data-native-capture=\"false\"] .gf-mainmenu-selected-proxy {\r\n  opacity: 1;\r\n}\r\n.gf-mainmenu[data-transitioning=\"true\"] .gf-mainmenu-selected-proxy {\r\n  transform: translate(-50%, -50%) scale(1.08);\r\n}\r\n.gf-mainmenu-selected-label {\r\n  position: relative;\r\n  z-index: 2;\r\n  color: var(--gf-yellow);\r\n  font-size: clamp(22px, 4vw, 58px);\r\n  line-height: 0.86;\r\n  letter-spacing: 0;\r\n  white-space: nowrap;\r\n  -webkit-text-stroke: clamp(2px, 0.32vw, 5px) #071126;\r\n  paint-order: stroke fill;\r\n  text-shadow:\r\n    0 3px 0 #ffffff,\r\n    0 7px 0 rgba(0, 0, 0, 0.52);\r\n}\r\n.gf-mainmenu-option-texture {\r\n  position: absolute;\r\n  right: 3%;\r\n  top: 3%;\r\n  width: min(24%, 300px);\r\n  image-rendering: pixelated;\r\n  opacity: 0;\r\n  pointer-events: none;\r\n  filter: drop-shadow(0 5px 0 rgba(0, 0, 0, 0.35));\r\n  transition: opacity var(--gf-native-tween-ms, 167ms) linear;\r\n}\r\n.gf-mainmenu[data-mode=\"option\"] .gf-mainmenu-option-texture {\r\n  opacity: 0.88;\r\n}\r\n\r\n/* ============================ LOAD BOX DATA ============================ */\r\n.gf-load-box { background: #f3a312; }\r\n/*\r\n * Real exported text plate (vsel00_mdl texture_004, ASSETS.vsSelectLabels) —\r\n * \"LOAD BOX DATA\" / \"Insert Memory Card into Slot A\" / \"and press the (A)\r\n * Button.\" — shown as the actual screen art instead of recreated CSS copy.\r\n * The sheet is a shared multi-line atlas (also used by BattleIntro.ts), so it\r\n * is displayed at natural aspect ratio near the top of the screen rather than\r\n * pixel-cropped to a single line.\r\n */\r\n.gf-load-label-sheet {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 6%;\r\n  width: min(72vw, 620px);\r\n  transform: translateX(-50%);\r\n  image-rendering: pixelated;\r\n  z-index: 2;\r\n  filter: drop-shadow(0 4px 0 rgba(0, 0, 0, 0.28));\r\n}\r\n.gf-load-memory-icon {\r\n  display: block;\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 46%;\r\n  width: clamp(42px, 7.8vw, 64px);\r\n  height: auto;\r\n  transform: translateX(-50%);\r\n  z-index: 2;\r\n  image-rendering: pixelated;\r\n  filter: drop-shadow(0 3px 0 rgba(0, 0, 0, 0.28));\r\n}\r\n.gf-box-model {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 12%;\r\n  width: min(44vw, 420px);\r\n  height: min(28vw, 270px);\r\n  transform: translateX(-50%);\r\n  z-index: 2;\r\n}\r\n.gf-box-model .gf-ui-scene-canvas {\r\n  display: block;\r\n  width: 100%;\r\n  height: 100%;\r\n  filter: drop-shadow(0 28px 20px rgba(0, 0, 0, 0.38));\r\n}\r\n\r\n/* ============================ SELECT A FORCE ============================ */\r\n/*\r\n * Rebuilt against reference/captures/challenge-5-select-a-force.png: the green\r\n * force-display platform is a captureCropImg crop of the real baked frame (see\r\n * SelectForce.ts doc comment), layered over the entry00 scene as atmospheric\r\n * backdrop. Dynamic COST/No./name/REMAIN render via bitmapText (ascii.tpl).\r\n */\r\n.gf-select-force { background: #8b4fb5; }\r\n.gf-select-force > .gf-select-title {\r\n  position: absolute;\r\n  left: var(--gf-select-title-left, 0);\r\n  top: var(--gf-select-title-top, 2%);\r\n  width: var(--gf-select-title-width, 100%);\r\n  z-index: 3;\r\n  padding-top: 0;\r\n  display: flex;\r\n  justify-content: center;\r\n}\r\n.gf-select-entry-scene {\r\n  opacity: 0.5;\r\n  transform: scale(1.04);\r\n  z-index: 1;\r\n}\r\n.gf-select-entry-scene .gf-ui-scene-canvas {\r\n  filter: drop-shadow(0 18px 18px rgba(0, 0, 0, 0.32));\r\n}\r\n.gf-select-pad-crop {\r\n  position: absolute;\r\n  left: var(--gf-select-pad-left, 50%);\r\n  top: var(--gf-select-pad-top, 47%);\r\n  width: min(var(--gf-select-pad-width, 58%), 620px);\r\n  aspect-ratio: 2410 / 300;\r\n  transform: translate(-50%, -50%);\r\n  overflow: hidden;\r\n  z-index: 1;\r\n  filter: drop-shadow(0 16px 14px rgba(0, 0, 0, 0.32));\r\n}\r\n.gf-select-pad {\r\n  /* Invisible hosting region for the live borg model/mini-icon fallback,\r\n     centered above the real platform-crop pad image. */\r\n  position: absolute;\r\n  left: var(--gf-select-pad-left, 50%);\r\n  top: var(--gf-select-pad-top, 47%);\r\n  width: min(var(--gf-select-pad-width, 45%), 420px);\r\n  height: min(var(--gf-select-pad-height, 17%), 150px);\r\n  transform: translate(-50%, -138%);\r\n  z-index: 2;\r\n}\r\n.gf-select-face,\r\n.gf-select-mini {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 6%;\r\n  max-width: 60%;\r\n  max-height: 220%;\r\n  object-fit: contain;\r\n  transform: translate(-50%, 0);\r\n  image-rendering: pixelated;\r\n  filter: drop-shadow(0 10px 0 rgba(0, 0, 0, 0.32));\r\n}\r\n.gf-select-mini-fallback {\r\n  display: flex;\r\n  align-items: flex-end;\r\n  justify-content: center;\r\n  max-width: 90%;\r\n}\r\n.gf-select-borg-scene {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 0;\r\n  width: min(30vw, 280px);\r\n  height: min(40vw, 360px);\r\n  transform: translate(-50%, 34%);\r\n  pointer-events: none;\r\n  filter: drop-shadow(0 14px 0 rgba(0, 0, 0, 0.32));\r\n}\r\n.gf-select-cost {\r\n  position: absolute;\r\n  left: 6%;\r\n  top: 66%;\r\n  /* Cap the block so it can never run under the force-name grid on the right. */\r\n  max-width: 34%;\r\n  z-index: 3;\r\n  display: flex;\r\n  align-items: baseline;\r\n  gap: 12px;\r\n  filter: drop-shadow(0 3px 0 rgba(0, 0, 0, 0.38));\r\n}\r\n.gf-select-name {\r\n  position: absolute;\r\n  right: 7%;\r\n  top: 64%;\r\n  z-index: 3;\r\n  display: grid;\r\n  grid-template-columns: auto minmax(120px, 1fr);\r\n  grid-template-areas:\r\n    \"no banner\"\r\n    \"force force\"\r\n    \"limit limit\";\r\n  gap: 6px 14px;\r\n  align-items: center;\r\n  /* Never overlap the COST readout on the left. */\r\n  width: min(52%, 520px);\r\n}\r\n.gf-select-no { grid-area: no; }\r\n.gf-select-banner {\r\n  grid-area: banner;\r\n  width: 100%;\r\n  max-width: 448px;\r\n  image-rendering: pixelated;\r\n  filter: drop-shadow(0 3px 0 rgba(0, 0, 0, 0.35));\r\n}\r\n.gf-select-banner-fallback { grid-area: banner; }\r\n.gf-select-force-name { grid-area: force; }\r\n.gf-select-limit { grid-area: limit; justify-self: end; }\r\n\r\n/* ============================ BATTLE INTRO ============================ */\r\n/*\r\n * Rebuilt so the exported brif00 scene is the PRIMARY surface (promoted from a\r\n * faint low-opacity backdrop) — see BattleIntro.ts doc comment for why no\r\n * dedicated real capture exists for this screen. All dynamic text (names,\r\n * arena, energy, VS/objective copy) renders via bitmapText (ascii.tpl).\r\n */\r\n.gf-battle-intro {\r\n  background:\r\n    radial-gradient(circle at 50% 50%, rgba(255, 255, 255, 0.08), transparent 52%),\r\n    linear-gradient(90deg, rgba(20, 78, 156, 0.82), rgba(137, 56, 155, 0.72));\r\n  pointer-events: auto;\r\n}\r\n.gf-brief-real-scene {\r\n  opacity: 0.92;\r\n  filter: drop-shadow(0 22px 20px rgba(0, 0, 0, 0.4));\r\n}\r\n.gf-brief-title {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 5%;\r\n  transform: translateX(-50%);\r\n  margin: 0;\r\n  z-index: 3;\r\n  width: min(86%, 860px);\r\n  text-align: center;\r\n  padding-top: 0;\r\n  display: flex;\r\n  justify-content: center;\r\n}\r\n.gf-brief-side {\r\n  position: absolute;\r\n  top: 25%;\r\n  z-index: 3;\r\n  width: min(32vw, 300px);\r\n  min-height: 42%;\r\n  display: grid;\r\n  justify-items: center;\r\n  align-content: start;\r\n  gap: 10px;\r\n}\r\n.gf-brief-player { left: 6%; }\r\n.gf-brief-enemy { right: 6%; }\r\n.gf-brief-icon,\r\n.gf-brief-emblem {\r\n  width: min(24vw, 220px);\r\n  aspect-ratio: 1;\r\n  object-fit: contain;\r\n  image-rendering: pixelated;\r\n  filter: drop-shadow(0 8px 0 rgba(0, 0, 0, 0.35));\r\n}\r\n.gf-brief-emblem {\r\n  border-radius: 50%;\r\n  background: radial-gradient(circle, var(--gf-yellow), var(--gf-red));\r\n}\r\n.gf-brief-energy,\r\n.gf-brief-name {\r\n  padding: 4px 16px;\r\n  border-radius: 999px;\r\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.22), 0 3px 0 rgba(0, 0, 0, 0.24);\r\n  display: flex;\r\n  justify-content: center;\r\n}\r\n.gf-brief-energy-player { background: linear-gradient(#3ea6ff, #1262c8); }\r\n.gf-brief-energy-enemy { background: linear-gradient(#ff5d4c, #b81d1a); }\r\n.gf-brief-name {\r\n  max-width: 100%;\r\n  background: linear-gradient(#fff2a8, #dc9f18);\r\n}\r\n.gf-brief-vs {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: 42%;\r\n  transform: translate(-50%, -50%) rotate(-8deg);\r\n  z-index: 4;\r\n}\r\n.gf-brief-vs-text { transform: scale(1.4); }\r\n.gf-brief-preview {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: 16%;\r\n  transform: translateX(-50%);\r\n  z-index: 2;\r\n  width: min(44vw, 470px);\r\n  height: min(18vw, 170px);\r\n  border: 5px solid rgba(255, 255, 255, 0.8);\r\n  border-radius: 10px;\r\n  background: rgba(0, 0, 0, 0.2);\r\n  box-shadow: inset 0 0 0 3px rgba(0, 0, 0, 0.28), 0 8px 0 rgba(0, 0, 0, 0.35);\r\n}\r\n.gf-brief-objective {\r\n  position: absolute;\r\n  left: 50%;\r\n  bottom: -22px;\r\n  transform: translateX(-50%);\r\n  width: max-content;\r\n  max-width: 92vw;\r\n  padding: 7px 24px;\r\n  border-radius: 999px;\r\n  background: linear-gradient(#ffd969, #e9a51a);\r\n  box-shadow: 0 3px 0 rgba(0, 0, 0, 0.35);\r\n}\r\n.gf-brief-arena-name {\r\n  position: absolute;\r\n  left: 50%;\r\n  top: -18px;\r\n  transform: translateX(-50%);\r\n  width: max-content;\r\n  max-width: 92vw;\r\n  padding: 5px 20px;\r\n  border-radius: 999px;\r\n  background: rgba(0, 0, 0, 0.55);\r\n  box-shadow: 0 3px 0 rgba(0, 0, 0, 0.3);\r\n}\r\n\r\n/* ============================ FORCE BUILDER ============================ */\r\n/*\r\n * Rebuilt against reference/captures/challenge-6-edit-force.png: the EDIT tab\r\n * and active-force banner are captureCropImg crops of the real baked plates;\r\n * the borg grid sits over a captureCropImg crop of the real checkered floor;\r\n * each of the 30 ring slots is textured with a captureCropImg crop of one real\r\n * hex tile (see ForceBuilder.ts's COMPROMISE doc comment for why the full ring\r\n * isn't a single crop). Dynamic COST/LIMIT/REMAIN/names render via bitmapText.\r\n */\r\n.gf-force-screen {\r\n  background: #0e2138;\r\n}\r\n.gf-force-unitall-scene {\r\n  left: 10px;\r\n  top: 54px;\r\n  right: calc(42% + 24px);\r\n  bottom: 68px;\r\n  z-index: 3;\r\n  opacity: 0.16;\r\n  transform: scale(1.03);\r\n  transform-origin: center;\r\n  mix-blend-mode: screen;\r\n  filter: saturate(1.18) drop-shadow(0 18px 18px rgba(0, 0, 0, 0.36));\r\n}\r\n.gf-force { position: relative; z-index: 2; display: grid; grid-template-columns: 1fr minmax(280px, 42%); gap: 12px; padding: 12px; box-sizing: border-box; height: 100%; }\r\n.gf-force-screen .gf-legend { z-index: 4; }\r\n.gf-force-edit-tab-crop {\r\n  position: relative;\r\n  align-self: start;\r\n  width: min(100%, 420px);\r\n  aspect-ratio: 900 / 210;\r\n  overflow: hidden;\r\n  border-radius: 999px;\r\n  filter: drop-shadow(0 3px 4px rgba(0, 0, 0, 0.4));\r\n}\r\n.gf-force-left { position: relative; display: flex; flex-direction: column; gap: 10px; min-height: 0; }\r\n.gf-force-floor-crop {\r\n  position: relative;\r\n  flex: 1;\r\n  min-height: 0;\r\n  overflow: hidden;\r\n  border-radius: 10px;\r\n  border: 2px solid #2f5e96;\r\n}\r\n.gf-force-floor-crop .gf-capture-crop-img { image-rendering: pixelated; }\r\n.gf-borg-grid {\r\n  position: absolute;\r\n  inset: 0;\r\n  overflow-y: auto;\r\n  display: grid;\r\n  /* The real extracted per-borg art (`mn<code>`) is a 224x32 name plate, not a\r\n     square icon, so each option is a wide row: [name plate | cost]. */\r\n  grid-template-columns: repeat(auto-fill, minmax(168px, 1fr));\r\n  gap: 6px;\r\n  padding: 10px;\r\n  align-content: start;\r\n}\r\n.gf-borg-cell {\r\n  position: relative;\r\n  height: 30px;\r\n  display: flex;\r\n  align-items: center;\r\n  justify-content: space-between;\r\n  gap: 4px;\r\n  border-radius: 8px;\r\n  background: linear-gradient(rgba(139, 147, 165, 0.92), rgba(92, 99, 116, 0.92));\r\n  border: 2px solid #b9c4d3;\r\n  cursor: pointer;\r\n  overflow: hidden;\r\n  padding: 2px 4px;\r\n}\r\n.gf-borg-cell img {\r\n  flex: 1;\r\n  min-width: 0;\r\n  height: 100%;\r\n  object-fit: contain;\r\n  object-position: left center;\r\n  image-rendering: pixelated;\r\n}\r\n.gf-borg-cell .gf-borg-cell-name {\r\n  flex: 1;\r\n  min-width: 0;\r\n  overflow: hidden;\r\n}\r\n.gf-borg-cell.gf-in-force { border-color: var(--gf-yellow); box-shadow: 0 0 0 2px var(--gf-yellow) inset; }\r\n.gf-borg-cell.gf-disabled { opacity: 0.35; cursor: not-allowed; }\r\n.gf-borg-cell.gf-cursor { box-shadow: 0 0 0 2px #fff, 0 0 8px 2px rgba(255, 255, 255, 0.6); }\r\n.gf-borg-cell .gf-cost-tag {\r\n  flex: none;\r\n  background: rgba(0, 0, 0, 0.7);\r\n  padding: 1px 4px;\r\n  border-radius: 4px;\r\n}\r\n.gf-borg-cell .gf-new-badge {\r\n  position: absolute;\r\n  top: 0;\r\n  left: 0;\r\n  font-size: 8px;\r\n  color: var(--gf-yellow);\r\n  background: var(--gf-red);\r\n  padding: 0 3px;\r\n  border-bottom-right-radius: 4px;\r\n  -webkit-text-stroke: 0.4px var(--gf-outline);\r\n  z-index: 1;\r\n}\r\n\r\n.gf-force-right {\r\n  position: relative;\r\n  display: flex;\r\n  flex-direction: column;\r\n  align-items: center;\r\n  border-radius: 10px;\r\n  background: radial-gradient(circle at 60% 50%, #3a2a6e, #1c1340);\r\n  border: 3px solid var(--gf-edit-purple);\r\n  padding: 10px;\r\n  min-height: 0;\r\n}\r\n.gf-force-banner {\r\n  position: relative;\r\n  align-self: stretch;\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 8px;\r\n  height: 40px;\r\n  margin-bottom: 8px;\r\n  overflow: hidden;\r\n}\r\n.gf-force-banner-crop {\r\n  position: absolute;\r\n  inset: 0;\r\n  overflow: hidden;\r\n  border-radius: 999px;\r\n  z-index: 0;\r\n}\r\n.gf-force-banner-mini {\r\n  position: relative;\r\n  z-index: 1;\r\n  height: 26px;\r\n  margin-left: 44px;\r\n  image-rendering: pixelated;\r\n}\r\n.gf-force-banner-name {\r\n  position: relative;\r\n  z-index: 1;\r\n}\r\n.gf-borg-ring {\r\n  position: relative;\r\n  width: 100%;\r\n  flex: 1;\r\n  min-height: 200px;\r\n}\r\n/*\r\n * Ring band: sampled navy/purple color from the capture rather than an image\r\n * crop (see ForceBuilder.ts COMPROMISE doc — no single real texture covers all\r\n * 30 procedurally-placed slot positions).\r\n */\r\n.gf-borg-ring::before {\r\n  content: \"\";\r\n  position: absolute;\r\n  inset: 6%;\r\n  border-radius: 50%;\r\n  background: radial-gradient(circle at 50% 50%, transparent 62%, var(--gf-edit-purple) 63% 78%, #8f7fc9 79% 82%, transparent 83%);\r\n  pointer-events: none;\r\n  z-index: 0;\r\n}\r\n.gf-hexcell {\r\n  position: absolute;\r\n  width: 34px;\r\n  height: 34px;\r\n  transform: translate(-50%, -50%);\r\n  display: grid;\r\n  place-items: center;\r\n  cursor: pointer;\r\n  border: 0;\r\n  background: none;\r\n  padding: 0;\r\n  overflow: hidden;\r\n  z-index: 1;\r\n}\r\n.gf-hexcell-hex-tile {\r\n  position: absolute;\r\n  inset: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  max-width: none;\r\n  object-fit: fill;\r\n  z-index: 0;\r\n}\r\n.gf-hexcell.gf-hexcell-empty .gf-hexcell-hex-tile { filter: grayscale(0.6) brightness(0.55) saturate(0.7); }\r\n.gf-hexcell-no {\r\n  position: relative;\r\n  z-index: 1;\r\n  transform: scale(0.85);\r\n}\r\n.gf-hexcell.gf-hexcell-filled .gf-hexcell-no { display: none; }\r\n.gf-hexcell-img {\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 1;\r\n  width: 88%;\r\n  height: 88%;\r\n  margin: auto;\r\n  object-fit: contain;\r\n  image-rendering: pixelated;\r\n}\r\n.gf-hexcell.gf-hexcell-active { filter: drop-shadow(0 0 0 2px var(--gf-red)); }\r\n.gf-hexcell.gf-cursor { filter: drop-shadow(0 0 3px #fff) drop-shadow(0 0 6px #fff); }\r\n\r\n.gf-cost-panel {\r\n  position: absolute;\r\n  right: 6%;\r\n  top: 38%;\r\n  width: 46%;\r\n  background: linear-gradient(#1f3f6e, #172e56);\r\n  border: 2px solid #b3b3b3;\r\n  border-radius: 4px;\r\n  padding: 6px 8px;\r\n  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.5);\r\n}\r\n.gf-cost-panel .gf-cost-line {\r\n  display: flex;\r\n  justify-content: space-between;\r\n  align-items: baseline;\r\n  gap: 8px;\r\n}\r\n.gf-cost-panel .gf-cost-total {\r\n  border-bottom: 2px solid #9aa0ab;\r\n  padding-bottom: 4px;\r\n  margin-bottom: 4px;\r\n}\r\n.gf-cost-panel .gf-cost-val { transform: scale(0.9); }\r\n.gf-cost-panel.gf-over .gf-cost-val.gf-remain { filter: hue-rotate(0deg); }\r\n.gf-force-legend .gf-legend-item { display: inline-flex; align-items: center; gap: 6px; }\r\n.gf-legend-glyph { opacity: 0.9; }\r\n\r\n/* ============================ BATTLE HUD ============================ */\r\n/* Rebuilt 1:1 against reference/captures/challenge-8-in-battle-hud.png and\r\n   challenge-9-battle-critical-hp.png. The HUD is authored on the game's\r\n   native 640x480 frame; BattleHud.ts scales the whole stage to the container\r\n   (non-uniform, like the real frame stretching to the viewport). All element\r\n   positions live in BattleHud.ts with the capture-measured %s commented. */\r\n.gf-hud {\r\n  position: absolute;\r\n  left: 0;\r\n  top: 0;\r\n  width: 640px;\r\n  height: 480px;\r\n  transform-origin: 0 0;\r\n  pointer-events: none;\r\n  z-index: 10;\r\n}\r\n.gf-hud .gf-hidden {\r\n  display: none;\r\n}\r\n.gf-hud-vector {\r\n  position: absolute;\r\n  inset: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  overflow: visible;\r\n}\r\n/* absolutely positioned real ascii.tpl bitmap text on the 640x480 stage */\r\n.gf-hud-text {\r\n  position: absolute;\r\n}\r\n/*\r\n * TUNED readability guard: the ascii.tpl bold block bakes in a black outline\r\n * (see bitmapText.ts), which is enough contrast for every HUD text node that\r\n * sits on its own solid/translucent plate (energy tabs, alert roundel, timer\r\n * pill, X/B button discs, critical HP capsule). A few elements float BARE\r\n * over the raw 3D scene with nothing behind them but the stage's fog/clear\r\n * color: the at-rest HP ring digits, ammo/X-ammo digits, the DEFEATED\r\n * banner, and the \"1P\"/\"2P\" player tag. Checked against the real 40-stage\r\n * render-state export extremes (st10 fog #000000, luma 0; st0b/st24/st2b/\r\n * st44/st4b fog #e8ffe8, luma ~248 — see research/asset-coverage audit) the\r\n * single baked outline plus the pre-existing 1px drop-shadow was too weak on\r\n * the near-white stages (verified with a throwaway harness rendering\r\n * BattleHud.ts directly over #000000 and #e8ffe8). This four-direction dark\r\n * halo is a presentation-only addition (no ROM/HUD-sprite source — the\r\n * decoded HUD has no separate text-shadow layer) sized to stay under the\r\n * glyphs' own baked outline so it does not change their read shape.\r\n */\r\n.gf-hp-num .gf-bitmap-glyph,\r\n.gf-ammo-num .gf-bitmap-glyph,\r\n.gf-xammo-num .gf-bitmap-glyph,\r\n.gf-defeated-text .gf-bitmap-glyph,\r\n.gf-player-label .gf-bitmap-glyph {\r\n  filter: drop-shadow(1px 0 0 rgba(10, 14, 30, 0.9)) drop-shadow(-1px 0 0 rgba(10, 14, 30, 0.9))\r\n    drop-shadow(0 1px 0 rgba(10, 14, 30, 0.9)) drop-shadow(0 -1px 0 rgba(10, 14, 30, 0.9));\r\n}\r\n/* ally energy number is centered in its tab segment (x 196..242 measured) */\r\n.gf-ally-num {\r\n  width: 46px;\r\n  justify-content: center;\r\n}\r\n/* HP digits move into the red capsule in the critical state (challenge-9) */\r\n.gf-hp-num.gf-critical {\r\n  left: 66px !important;\r\n  top: 402px !important;\r\n}\r\n/* top-center timer pill (untimed challenge battles hide it) */\r\n.gf-hud-timer {\r\n  position: absolute;\r\n  top: 8px;\r\n  left: 320px;\r\n  transform: translateX(-50%);\r\n  min-width: 78px;\r\n  height: 26px;\r\n  display: grid;\r\n  place-items: center;\r\n  border-radius: 999px;\r\n  background: linear-gradient(#eef2f7, #9aa0ab);\r\n  border: 2px solid #ffffff;\r\n  box-shadow: inset 0 -3px 0 rgba(0, 0, 0, 0.24);\r\n}\r\n.gf-hud-timer.gf-hidden {\r\n  display: none;\r\n}\r\n/* real per-borg bn<code> name banner (optional slot) */\r\n.gf-hud-banner {\r\n  position: absolute;\r\n  top: 40px;\r\n  left: 320px;\r\n  transform: translateX(-50%);\r\n  height: 28px;\r\n  image-rendering: pixelated;\r\n}\r\n/* floating teammate plates (\"CPU\"/\"ALLY\" + green-on-red mini HP bar).\r\n   challenge-8 example: CPU label at 56..60%W / 21.5..23.5%H, bar 63x6px below. */\r\n.gf-hud-mates {\r\n  position: absolute;\r\n  inset: 0;\r\n}\r\n.gf-mate {\r\n  position: absolute;\r\n  transform: translateX(-50%);\r\n  display: grid;\r\n  grid-template-columns: 18px 63px;\r\n  grid-template-rows: auto auto;\r\n  column-gap: 4px;\r\n  row-gap: 3px;\r\n  align-items: center;\r\n}\r\n.gf-mate-roundel {\r\n  grid-row: 1 / 3;\r\n  width: 18px;\r\n  height: 18px;\r\n  object-fit: contain;\r\n  image-rendering: pixelated;\r\n  filter: drop-shadow(1px 1px 0 rgba(16, 24, 60, 0.75));\r\n}\r\n.gf-mate-label {\r\n  grid-column: 2;\r\n  min-width: 63px;\r\n  height: 18px;\r\n}\r\n/*\r\n * TUNED readability guard (matches the .gf-hp-num/.gf-ammo-num etc. rule\r\n * above): the floating teammate label has no backing plate and uses the\r\n * THIN (untinted-white, no baked outline) ascii.tpl block, so a single 1px\r\n * diagonal shadow measured too weak against the near-white stage extremes\r\n * (st0b/st24/st2b/st44/st4b) in the readability harness. Widened to a\r\n * four-direction halo for the same reason.\r\n */\r\n.gf-mate-label .gf-bitmap-glyph {\r\n  filter: drop-shadow(1px 0 0 rgba(16, 24, 60, 0.9)) drop-shadow(-1px 0 0 rgba(16, 24, 60, 0.9))\r\n    drop-shadow(0 1px 0 rgba(16, 24, 60, 0.9)) drop-shadow(0 -1px 0 rgba(16, 24, 60, 0.9));\r\n}\r\n.gf-mate-bar {\r\n  grid-column: 2;\r\n  width: 63px;\r\n  height: 6px;\r\n  background: #f2200a;\r\n  border: 1px solid rgba(0, 0, 0, 0.7);\r\n}\r\n.gf-mate-fill {\r\n  height: 100%;\r\n  background: #2ce518;\r\n}\r\n\r\n/* ============================ RESULTS ============================ */\r\n/*\r\n * Rebuilt so the exported rpot20 (win) / rpot23 (lose) podium scene is the\r\n * PRIMARY surface (promoted from a faint backdrop). Row LABELS are one real\r\n * captureCropImg crop of the baked pill stack (fixed text, same every result);\r\n * per-battle VALUES render via bitmapText. See Results.ts doc comment.\r\n */\r\n.gf-results { background: #6a3f2a; }\r\n.gf-results::after {\r\n  content: \"\";\r\n  position: absolute;\r\n  inset: 0;\r\n  z-index: 1;\r\n  background: linear-gradient(90deg, rgba(0, 0, 0, 0.28), rgba(0, 0, 0, 0.04) 54%, rgba(0, 0, 0, 0.12));\r\n  pointer-events: none;\r\n}\r\n.gf-results-real-scene {\r\n  z-index: 0;\r\n  opacity: 1;\r\n  filter: drop-shadow(0 20px 20px rgba(0, 0, 0, 0.38));\r\n}\r\n/*\r\n * Row horizontal extent comes from the rpot20/rpot23 scene exports (row pills\r\n * normalized against the 640x480 screen quad) via vars set in Results.ts; the\r\n * vertical placement stays hand-tuned because the export is a rest pose (see\r\n * the generated anchor's caveat). Fallbacks preserve the hand-tuned layout.\r\n */\r\n.gf-results-labels-crop {\r\n  position: absolute;\r\n  left: var(--gf-results-rows-left, 6%);\r\n  top: 6%;\r\n  height: 88%;\r\n  aspect-ratio: 785 / 1355;\r\n  overflow: hidden;\r\n  z-index: 2;\r\n  filter: drop-shadow(0 3px 3px rgba(0, 0, 0, 0.3));\r\n}\r\n.gf-results-rows {\r\n  position: absolute;\r\n  left: var(--gf-results-rows-left, 6%);\r\n  top: 6%;\r\n  height: 88%;\r\n  aspect-ratio: 785 / 1355;\r\n  display: flex;\r\n  flex-direction: column;\r\n  z-index: 3;\r\n}\r\n.gf-result-row { flex: 1; display: flex; align-items: center; }\r\n.gf-result-label-spacer { flex: 1.8; }\r\n.gf-result-val {\r\n  flex: 1;\r\n  display: flex;\r\n  justify-content: flex-end;\r\n  padding-right: 6%;\r\n}\r\n.gf-result-grand .gf-result-val { padding-right: 4%; }\r\n.gf-results-verdict {\r\n  position: absolute;\r\n  left: 42%;\r\n  top: 44%;\r\n  transform: translate(-50%, -50%) rotate(-6deg);\r\n  z-index: 3;\r\n}\r\n.gf-verdict-win .gf-bitmap-text { filter: drop-shadow(0 4px 0 rgba(0, 0, 0, 0.4)); }\r\n.gf-verdict-lose {\r\n  left: 50%;\r\n  top: 36%;\r\n  transform: translate(-50%, -50%) rotate(-3deg);\r\n}\r\n.gf-results-start {\r\n  position: absolute;\r\n  right: 18px;\r\n  bottom: 18px;\r\n  z-index: 4;\r\n  padding: 6px 14px;\r\n  border-radius: 999px;\r\n  background: rgba(0, 0, 0, 0.55);\r\n  filter: drop-shadow(0 3px 0 rgba(0, 0, 0, 0.35));\r\n}\r\n\r\n/* ============================ PAUSE MENU ============================ */\r\n.gf-pause-overlay {\r\n  position: absolute;\r\n  inset: 0;\r\n  display: grid;\r\n  place-items: center;\r\n  background: rgba(0, 0, 0, 0.18);\r\n  z-index: 20;\r\n}\r\n/*\r\n * RECREATED (no original pause-menu asset found) — see PauseMenu.ts header.\r\n * The panel reuses an existing exported glossy roundel plate texture\r\n * (ASSETS.menuRoundelPlate) as its backing art instead of a flat CSS gradient\r\n * box; the purple border/shape remain a minimal, gamepad-safe recreation.\r\n */\r\n.gf-pause-panel {\r\n  position: relative;\r\n  min-width: 260px;\r\n  border-radius: 16px;\r\n  background: #aeb4c0;\r\n  border: 4px solid var(--gf-edit-purple);\r\n  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.5);\r\n  overflow: hidden;\r\n}\r\n.gf-pause-plate {\r\n  position: absolute;\r\n  inset: 0;\r\n  width: 100%;\r\n  height: 100%;\r\n  object-fit: cover;\r\n  opacity: 0.55;\r\n  mix-blend-mode: luminosity;\r\n  pointer-events: none;\r\n  z-index: 0;\r\n}\r\n.gf-pause-panel > :not(.gf-pause-plate) {\r\n  position: relative;\r\n  z-index: 1;\r\n}\r\n.gf-pause-title {\r\n  min-height: 42px;\r\n  display: grid;\r\n  place-items: center;\r\n  padding: 8px 0;\r\n  color: var(--gf-outline);\r\n}\r\n.gf-pause-items { padding: 8px 14px 16px; display: flex; flex-direction: column; gap: 8px; }\r\n.gf-pause-item {\r\n  display: flex;\r\n  align-items: center;\r\n  gap: 10px;\r\n  min-height: 36px;\r\n  padding: 6px 12px;\r\n  border-radius: 999px;\r\n  background: rgba(255, 255, 255, 0.4);\r\n  color: var(--gf-outline);\r\n  cursor: pointer;\r\n  border: none;\r\n  font-family: inherit;\r\n  font-weight: 800;\r\n}\r\n.gf-pause-item.gf-selected {\r\n  background: linear-gradient(#6f9bd8, #2f6db0);\r\n  color: #fff;\r\n}\r\n.gf-pause-item .gf-pause-bullet { width: 1.4em; }\r\n.gf-pause-title-text {\r\n  transform: scale(2.65);\r\n  transform-origin: center;\r\n  filter: drop-shadow(1px 1px 0 rgba(255, 255, 255, 0.55));\r\n}\r\n.gf-pause-item-text {\r\n  transform: scale(2.15);\r\n  transform-origin: left center;\r\n  filter: drop-shadow(1px 1px 0 rgba(255, 255, 255, 0.45));\r\n}\r\n.gf-pause-item.gf-selected .gf-pause-item-text {\r\n  filter: drop-shadow(1px 1px 0 rgba(0, 0, 0, 0.65));\r\n}\r\n\r\n/* ============================ GETS (Borg GET drop list) ============================ */\r\n/* TUNED minimal recreation — see Gets.ts header. Deliberately simple: a static list of\r\n   this battle's rolled drops over the real getStrip (gets00_mdl) texture, no per-drop\r\n   box-open cinematic (future work). */\r\n.gf-gets {\r\n  background: #1a2f4a;\r\n  display: grid;\r\n  place-items: center;\r\n}\r\n.gf-gets-backdrop {\r\n  position: absolute;\r\n  top: 8%;\r\n  left: 50%;\r\n  transform: translateX(-50%);\r\n  width: min(80vw, 448px);\r\n  image-rendering: pixelated;\r\n  filter: drop-shadow(0 6px 10px rgba(0, 0, 0, 0.4));\r\n  z-index: 0;\r\n}\r\n.gf-gets-title {\r\n  position: absolute;\r\n  top: 6%;\r\n  left: 50%;\r\n  transform: translateX(-50%) scale(3);\r\n  z-index: 2;\r\n  color: var(--gf-yellow);\r\n  filter: drop-shadow(1px 1px 0 var(--gf-outline));\r\n}\r\n.gf-gets-rows {\r\n  position: relative;\r\n  z-index: 1;\r\n  margin-top: 18%;\r\n  display: flex;\r\n  flex-direction: column;\r\n  gap: 14px;\r\n  min-width: min(80vw, 420px);\r\n}\r\n.gf-gets-row {\r\n  padding: 10px 18px;\r\n  border-radius: 999px;\r\n  background: linear-gradient(#7fb4e6, var(--gf-blue-pill-deep));\r\n  border: 2px solid #bcdcff;\r\n  box-shadow: inset 0 -2px 0 rgba(0, 0, 0, 0.25);\r\n  text-align: center;\r\n}\r\n.gf-gets-row-parts { background: linear-gradient(#f0c26a, #b5813a); border-color: #ffdf9c; }\r\n.gf-gets-row-text {\r\n  transform: scale(1.6);\r\n  transform-origin: center;\r\n  filter: drop-shadow(1px 1px 0 rgba(0, 0, 0, 0.55));\r\n}\r\n.gf-gets-prompt {\r\n  position: absolute;\r\n  right: 18px;\r\n  bottom: 18px;\r\n  z-index: 2;\r\n  color: #fff;\r\n  font-size: clamp(11px, 1.6vw, 15px);\r\n  letter-spacing: 0.06em;\r\n  -webkit-text-stroke: 0.5px var(--gf-outline);\r\n  paint-order: stroke fill;\r\n}\r\n";
